@page "/catalog"
@using sv_d2a7a34ff5b14ba497f6a647a561e15a.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout d-flex">
    <div class="catalog-sidebar">
        <CatalogSidebar Categories="@categories"
                        OnApplyFilter="HandleApplyFilter"
                        OnClearFilter="HandleClearFilter" />
    </div>

    <div class="catalog-main flex-grow-1 p-3">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="text-center py-5 text-muted">
                <h4>No products found</h4>
                <p>Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <div class="toolbar d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="me-2">Sort by:</label>
                    <select class="form-select d-inline-block w-auto"
                            value="@sortBy"
                            @onchange="HandleSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    Showing @(StartItem)–@(EndItem) of @result.TotalCount products
                </span>
            </div>

            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
                @foreach (var product in result.Items)
                {
                    <div class="col" @key="product.Id">
                        <ProductCard Product="product"
                                     OnSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    </div>
                }
            </div>

            @{ var totalPages = TotalPages; }
            @if (totalPages > 1)
            {
                <nav class="d-flex justify-content-center mt-4">
                    <ul class="pagination">
                        <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                    disabled="@(currentPage <= 1)">Previous</button>
                        </li>
                        @for (var i = 1; i <= totalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(currentPage >= totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                    disabled="@(currentPage >= totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;
    private bool isLoading = true;
    private string? errorMessage;

    private int StartItem => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int EndItem => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);
    private int TotalPages => result is null ? 0 : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilter(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleClearFilter()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        await Task.CompletedTask;
    }
}

.catalog-layout {
    min-height: calc(100vh - 4rem);
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    max-width: 300px;
    flex-shrink: 0;
}

.catalog-main {
    width: 75%;
}

